import React from 'react';
import { useMusic } from '../context/MusicContext';
import { Play, Pause, SkipBack, SkipForward, Heart, Volume2, ListMusic } from 'lucide-react';

const GlobalPlayer = () => {
  const { currentSong, isPlaying, togglePlay, handleNext, handlePrev, favorites, toggleLike } = useMusic();

  if (!currentSong) return null; // Không hiện player nếu chưa chọn bài

  const isLiked = favorites.includes(currentSong._id);

  return (
    <div style={playerWrapper}>
      {/* 1. Thông tin bài hát (Bên trái) */}
      <div style={songSection}>
        <img 
          src={`http://localhost:5000${currentSong.imageUrl}`} 
          alt={currentSong.title} 
          style={albumArt} 
        />
        <div style={textContainer}>
          <div style={songTitle}>{currentSong.title}</div>
          <div style={songArtist}>{currentSong.artist}</div>
        </div>
        <button onClick={() => toggleLike(currentSong._id)} style={btnIcon}>
          <Heart 
            size={20} 
            fill={isLiked ? "#1db954" : "none"} 
            color={isLiked ? "#1db954" : "#b3b3b3"} 
            style={{ transition: '0.3s' }}
          />
        </button>
      </div>

      {/* 2. Bộ điều khiển nhạc (Ở giữa) */}
      <div style={controlsSection}>
        <div style={btnGroup}>
          <button onClick={handlePrev} style={btnSecondary}><SkipBack size={22} fill="currentColor"/></button>
          <button onClick={togglePlay} style={btnMain}>
            {isPlaying ? <Pause size={24} fill="#000"/> : <Play size={24} fill="#000" style={{marginLeft: '3px'}}/>}
          </button>
          <button onClick={handleNext} style={btnSecondary}><SkipForward size={22} fill="currentColor"/></button>
        </div>
        {/* Thanh progress giả - có thể nâng cấp thêm logic sau */}
        <div style={progressBarContainer}>
          <div style={progressBg}><div style={progressFill}></div></div>
        </div>
      </div>

      {/* 3. Tiện ích (Bên phải) */}
      <div style={utilitySection}>
        <Volume2 size={20} color="#b3b3b3"/>
        <div style={volumeBar}></div>
        <ListMusic size={20} color="#b3b3b3" style={{marginLeft: '15px'}}/>
      </div>
    </div>
  );
};

/* --- STYLES --- */
const playerWrapper = {
  position: 'fixed', bottom: 0, left: 0, right: 0, height: '90px',
  background: '#181818', borderTop: '1px solid #282828',
  display: 'flex', alignItems: 'center', justifyContent: 'space-between',
  padding: '0 20px', zIndex: 2000, color: '#fff'
};

const songSection = { display: 'flex', alignItems: 'center', width: '30%', minWidth: '180px' };
const albumArt = { width: '56px', height: '56px', borderRadius: '4px', objectFit: 'cover' };
const textContainer = { marginLeft: '15px', marginRight: '15px', overflow: 'hidden' };
const songTitle = { fontSize: '14px', fontWeight: 'bold', whiteSpace: 'nowrap' };
const songArtist = { fontSize: '12px', color: '#b3b3b3', marginTop: '4px' };

const controlsSection = { display: 'flex', flexDirection: 'column', alignItems: 'center', width: '40%' };
const btnGroup = { display: 'flex', alignItems: 'center', gap: '20px', marginBottom: '8px' };
const btnMain = { background: '#fff', border: 'none', width: '35px', height: '35px', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer' };
const btnSecondary = { background: 'none', border: 'none', color: '#b3b3b3', cursor: 'pointer', display: 'flex', alignItems: 'center' };
const btnIcon = { background: 'none', border: 'none', cursor: 'pointer', padding: '5px' };

const progressBarContainer = { width: '100%', maxWidth: '500px' };
const progressBg = { height: '4px', background: '#4d4d4d', borderRadius: '2px', position: 'relative' };
const progressFill = { width: '30%', height: '100%', background: '#1db954', borderRadius: '2px' }; // Tạm thời để 30%

const utilitySection = { display: 'flex', alignItems: 'center', justifyContent: 'flex-end', width: '30%' };
const volumeBar = { width: '100px', height: '4px', background: '#4d4d4d', borderRadius: '2px', marginLeft: '10px' };

export default GlobalPlayer;
